749	/// POST /api/v1/chat/stream — SSE streaming endpoint (auth required).
750	///
751	/// Proxies to the failover router's `stream()` method, enabling stream
752	/// support for the full Council synthesis and fallback chain.
753	/// Each SSE event: `data: {"chunk": "...", "done": false}`
754	/// Final event:    `data: {"chunk": "", "done": true}`
755	pub async fn stream_handler(
756	    State(state): State<Arc<AppState>>,
757	    Json(req): Json<ChatRequest>,
758	) -> Response {
759	    // Security: prompt injection detection
760	    if detect_injection(&req.user) {
761	        tracing::warn!("Blocked potential prompt injection attempt in stream");
762	        let data =
763	            json!({"error": "Potentially unsafe prompt detected.", "done": true}).to_string();
764	        return Sse::new(futures::stream::once(async {
765	            Ok::<Event, String>(Event::default().data(data))
766	        }))
767	        .into_response();
768	    }
769	
770	    // Identity invariants enforcement in streaming path: bypass provider identity drift.
771	    if is_identity_probe(&req.user) {
772	        let first = json!({"chunk": REQUIRED_IDENTITY_RESPONSE, "done": false}).to_string();
773	        let done = json!({"chunk": "", "done": true}).to_string();
774	        let sse_stream = futures::stream::iter(vec![
775	            Ok::<Event, String>(Event::default().data(first)),
776	            Ok::<Event, String>(Event::default().data(done)),
777	        ]);
778	        return Sse::new(sse_stream).into_response();
779	    }
780	
781	    match state.router.stream(&req).await {
782	        Err(e) => {
783	            tracing::error!(error = %e, "stream provider error");
784	            (
785	                StatusCode::SERVICE_UNAVAILABLE,
786	                Json(json!({"detail": e.to_string()})),
787	            )
788	                .into_response()
789	        }
790	        Ok(chunk_stream) => {
791	            // Map each ChatChunk into an SSE Event.
792	            let sse_stream = chunk_stream.map(|result| match result {
793	                Ok(chunk) => {
794	                    let data = json!({"chunk": chunk.delta, "done": chunk.done}).to_string();
795	                    Ok::<Event, String>(Event::default().data(data))
796	                }
797	                Err(e) => {
798	                    let data = json!({"error": e.to_string(), "done": true}).to_string();
799	                    Ok(Event::default().data(data))
800	                }
801	            });
802	
803	            // Append a terminal done event after the provider stream ends.
804	            let terminal = futures::stream::once(async {
805	                let data = json!({"chunk": "", "done": true}).to_string();
806	                Ok::<Event, String>(Event::default().data(data))
807	            });
808	
809	            Sse::new(sse_stream.chain(terminal)).into_response()
810	        }
811	    }
812	}
