pub async fn chat_handler(
    State(state): State<Arc<AppState>>,
    Json(req): Json<ChatRequest>,
) -> impl IntoResponse {
    // Capture consensus_required before req is moved/mutated.
    // CollectiveBrain requests require consensus per CONSENSUS_ENGINE.md.
    let consensus_required = req.use_collectivebrain.unwrap_or(false);
    if consensus_required {
        tracing::debug!(
            "use_collectivebrain=true requested but CollectiveBrain is not yet implemented in Rust; \
             falling through to normal LLM routing — tagging trace as consensus_required"
        );
    }

    // Economic Integration: Charge the agent if agent_id is present.
    // Base cost for a standard chat request.
    let base_cost = 0.05_f32;
    if let Some(ref agent_id) = req.agent_id {
        // Auto-init with 10.0 credits if new.
        let _ = state.economy.init_wallet(agent_id, 10.0).await;

        if !state
            .economy
            .can_afford(agent_id, base_cost)
            .await
            .unwrap_or(false)
        {
            return (
                StatusCode::PAYMENT_REQUIRED,
                Json(json!({"detail": "Insufficient Neuro-Credits for this request.", "agent_id": agent_id})),
            ).into_response();
        }

        // Record the transaction before routing (pessimistic lock on budget).
        let _ = state
            .economy
            .record_transaction(
                agent_id,
                base_cost,
                TransactionType::Spend,
                &format!("Chat inference: {}", req.mode),
            )
            .await;
    }

    // Validate mode before routing — return 400 for unknown modes.
    if !is_valid_mode(&req.mode) {
        tracing::warn!(mode = %req.mode, "Rejected request with unknown mode");
        return (
            StatusCode::BAD_REQUEST,
            Json(json!({"detail": format!("Unknown mode '{}'.", req.mode)})),
        )
            .into_response();
    }

    // Security: prompt injection detection
    if detect_injection(&req.user) {
        tracing::warn!("Blocked potential prompt injection attempt");
        return (
            StatusCode::BAD_REQUEST,
            Json(json!({"detail": "Potentially unsafe prompt detected."})),
        )
            .into_response();
    }

    // Retrieve memory hits before routing so they can be included in the response.
    let memory_entries: Vec<MemoryEntry> = if req.use_memory {
        let mut merged = Vec::new();
        let mut seen = HashSet::new();
        for query in retrieval_queries(&req.user, &state) {
            let hits = state
                .memory_store
                .search(&query, 6)
                .await
                .unwrap_or_default();
            for entry in hits {
                let dedupe_key = entry
                    .id
                    .as_ref()
                    .map(|id| id.0.clone())
                    .unwrap_or_else(|| entry.content.chars().take(80).collect::<String>());
                if seen.insert(dedupe_key) {
                    merged.push(entry);
                }
                if merged.len() >= 6 {
                    break;
                }
            }
            if merged.len() >= 6 {
                break;
            }
        }
        merged
    } else {
        vec![]
    };
    let memory_hits: Vec<serde_json::Value> = memory_entries
        .iter()
        .cloned()
        .map(|e| serde_json::to_value(e).unwrap_or_default())
        .collect();

    if req.use_memory && state.config.memory_reinforce_enabled() && !memory_entries.is_empty() {
        let store = state.memory_store.clone();
        let cfg = state.config.clone();
        let entries = memory_entries.clone();
        tokio::spawn(async move { reinforce_memory_hits(store, &cfg, entries).await });
    }

    // Inject sovereign identity as system prompt prefix.
    // If the caller already provided a system prompt, append it after the identity block.
    // Use pre-rendered text cached on AppState — render_text() is not called per-request.
    let identity_text = &state.identity_text;
    let current_date = chrono::Utc::now()
        .format("Current date: %Y-%m-%d (UTC).")
        .to_string();
    let mut req = req;
    let memory_context = render_memory_context(&memory_entries);
    req.system = Some(match req.system.take() {
        Some(existing) => {
            let mut system = format!("{}\n{}", identity_text, current_date);
            if let Some(memory_context) = memory_context.as_ref() {
                system.push_str("\n\n");
                system.push_str(memory_context);
            }
            system.push_str("\n\n");
            system.push_str(&existing);
            system
        }
        None => {
            let mut system = format!("{}\n{}", identity_text, current_date);
            if let Some(memory_context) = memory_context.as_ref() {
                system.push_str("\n\n");
                system.push_str(memory_context);
            }
            system
        }
    });

    let started = Instant::now();
    let mode_label = req.mode.clone();
    let task_id = req.task_state.as_ref().and_then(|ts| ts.task_id.clone());
    let phase_transition_id = Uuid::new_v4().to_string();
    let retrieval_sources = retrieval_sources_from_hits(&memory_hits);
    let canon_anchor_weight = estimate_canon_anchor_weight(&state, &req);
    let intent_priority_score = estimate_intent_priority_score(&req, consensus_required);
    let authority_shrink_level =
        estimate_authority_shrink_level(&req, consensus_required, memory_hits.len());
    let resonance_amplitude =
        estimate_resonance_amplitude(&req, memory_hits.len(), consensus_required);
    let shear_index = estimate_shear_index(&req, memory_hits.len());
    let predicted_failure_modes =
        predicted_failure_modes(&req, memory_hits.len(), consensus_required);

    match state.router.route(&req).await {
        Ok(mut resp) => {
            // Output-layer contamination scan: replace known provider identity phrases
            // with OmegA-aligned equivalents before the response reaches the caller.
            resp.reply =
                scan_output_contamination(&resp.reply, &state.identity.contamination_signals);

            // Identity invariants enforcement (prevents identity drift/provider leakage).
            if is_identity_probe(&req.user) {
                resp.reply = REQUIRED_IDENTITY_RESPONSE.to_string();
            }

            // Inject real memory hits into the response (overrides the empty vec
            // that providers currently return).
            resp.memory_hits = memory_hits;

            let memory_context_loaded = !resp.memory_hits.is_empty();
            let provider_used = resp.mode.clone();
            let structural_integrity_score = estimate_structural_integrity_score(
                &TraceOutcome::Success,
                shear_index,
                authority_shrink_level,
                consensus_required,
            );

            // Record a trace event for this successful chat inference.
            let _ = state
                .trace
                .record(TraceEvent {
                    id: String::new(),
                    task_id: task_id.clone(),
                    agent: "gateway".to_string(),
                    phase: "execute".to_string(),
                    action: format!("chat/{mode_label}"),
                    outcome: TraceOutcome::Success,
                    duration_ms: started.elapsed().as_millis() as u64,
                    tokens: None,
                    error: None,
                    timestamp: chrono::Utc::now(),
                    provider_used: Some(provider_used),
                    retrieval_sources: retrieval_sources.clone(),
                    identity_shell_loaded: Some(true),
                    memory_context_loaded: Some(memory_context_loaded),
                    tool_invocations: None,
                    failure_tags: None,
                    consensus_required: Some(consensus_required),
                    consensus_outcome: if consensus_required {
                        Some("bypassed".to_string()) // CollectiveBrain not yet enforced
                    } else {
                        None
                    },
                    phase_state: Some("ACT".to_string()),
                    phase_transition_id: Some(phase_transition_id.clone()),
                    resonance_amplitude: Some(resonance_amplitude),
                    shear_index: Some(shear_index),
                    canon_anchor_weight: Some(canon_anchor_weight),
                    structural_integrity_score: Some(structural_integrity_score),
                    intent_priority_score: Some(intent_priority_score),
                    authority_shrink_level: Some(authority_shrink_level),
                    predicted_failure_modes: predicted_failure_modes.clone(),
                    actual_failure_mode: None,
                    promotion_decay_ratio: None,
                })
                .await;

            (StatusCode::OK, Json(resp)).into_response()
        }
        Err(e) => {
            tracing::error!(error = %e, "router error");
            let failure_tags = if consensus_required {
                vec!["RUNTIME_ENV".to_string(), "CONSENSUS_BYPASS".to_string()]
            } else {
                vec!["RUNTIME_ENV".to_string()]
            };
            let actual_failure_mode = failure_tags.first().cloned();
            let structural_integrity_score = estimate_structural_integrity_score(
                &TraceOutcome::Failure,
                shear_index,
                authority_shrink_level,
                consensus_required,
            );

            // Record a trace event for the failure.
            let _ = state
                .trace
                .record(TraceEvent {
                    id: String::new(),
                    task_id,
                    agent: "gateway".to_string(),
                    phase: "execute".to_string(),
                    action: format!("chat/{mode_label}"),
                    outcome: TraceOutcome::Failure,
                    duration_ms: started.elapsed().as_millis() as u64,
                    tokens: None,
                    error: Some(e.to_string()),
                    timestamp: chrono::Utc::now(),
                    provider_used: None,
                    retrieval_sources,
                    identity_shell_loaded: Some(true),
                    memory_context_loaded: None,
                    tool_invocations: None,
                    failure_tags: Some(failure_tags),
                    consensus_required: Some(consensus_required),
                    consensus_outcome: None,
                    phase_state: Some("ACT".to_string()),
                    phase_transition_id: Some(phase_transition_id),
                    resonance_amplitude: Some(resonance_amplitude),
                    shear_index: Some(shear_index),
                    canon_anchor_weight: Some(canon_anchor_weight),
                    structural_integrity_score: Some(structural_integrity_score),
                    intent_priority_score: Some(intent_priority_score),
                    authority_shrink_level: Some(authority_shrink_level),
                    predicted_failure_modes,
                    actual_failure_mode,
                    promotion_decay_ratio: None,
                })
                .await;

            (
                StatusCode::SERVICE_UNAVAILABLE,
                Json(json!({"detail": e.to_string()})),
            )
                .into_response()
        }
    }
}

/// POST /api/v1/chat/stream — SSE streaming endpoint (auth required).
///
/// Proxies to the failover router's `stream()` method, enabling stream
/// support for the full Council synthesis and fallback chain.
/// Each SSE event: `data: {"chunk": "...", "done": false}`
/// Final event:    `data: {"chunk": "", "done": true}`
pub async fn stream_handler(
    State(state): State<Arc<AppState>>,
    Json(req): Json<ChatRequest>,
) -> Response {
    // Security: prompt injection detection
    if detect_injection(&req.user) {
        tracing::warn!("Blocked potential prompt injection attempt in stream");
        let data =
            json!({"error": "Potentially unsafe prompt detected.", "done": true}).to_string();
        return Sse::new(futures::stream::once(async {
            Ok::<Event, String>(Event::default().data(data))
        }))
        .into_response();
    }

    // Identity invariants enforcement in streaming path: bypass provider identity drift.
    if is_identity_probe(&req.user) {
        let first = json!({"chunk": REQUIRED_IDENTITY_RESPONSE, "done": false}).to_string();
        let done = json!({"chunk": "", "done": true}).to_string();
        let sse_stream = futures::stream::iter(vec![
            Ok::<Event, String>(Event::default().data(first)),
            Ok::<Event, String>(Event::default().data(done)),
        ]);
        return Sse::new(sse_stream).into_response();
    }

    match state.router.stream(&req).await {
        Err(e) => {
            tracing::error!(error = %e, "stream provider error");
            (
                StatusCode::SERVICE_UNAVAILABLE,
                Json(json!({"detail": e.to_string()})),
            )
                .into_response()
        }
        Ok(chunk_stream) => {
            // Map each ChatChunk into an SSE Event.
            let sse_stream = chunk_stream.map(|result| match result {
                Ok(chunk) => {
                    let data = json!({"chunk": chunk.delta, "done": chunk.done}).to_string();
                    Ok::<Event, String>(Event::default().data(data))
                }
                Err(e) => {
                    let data = json!({"error": e.to_string(), "done": true}).to_string();
                    Ok(Event::default().data(data))
                }
            });

            // Append a terminal done event after the provider stream ends.
            let terminal = futures::stream::once(async {
                let data = json!({"chunk": "", "done": true}).to_string();
                Ok::<Event, String>(Event::default().data(data))
            });

            Sse::new(sse_stream.chain(terminal)).into_response()
        }
    }
}

/// Unified OmegA State Vector
///
/// Ω_t = ⟨Φ_t, E_t, τ_t, B_t, S_t, G_t^mem⟩
///
/// This module models the canonical state vector that flows through all four layers.
/// Each component is owned by one layer but visible to all:
///
/// - Φ_t (Phylactery)    :: AEON owns the identity chain
/// - E_t (Economy)        :: ADCCL owns neuro-credit accounting
/// - τ_t (Task)           :: AEON owns task state object
/// - B_t (Bridge)         :: Orchestration owns measurement and gates
/// - S_t (Semantic)       :: MYELIN owns retrieval path state
/// - G_t^mem (Memory)     :: MYELIN owns the graph structure

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use chrono::{DateTime, Utc};

/// Φ_t: Phylactery — Append-only identity canon chain
///
/// Owned by AEON. Maintains the commit history and identity vector
/// across all sessions. This is the authoritative record of "who we are
/// and how we got here."
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Phylactery {
    /// Unique identity fingerprint (stable across sessions)
    pub identity_vector: String,

    /// Ordered list of canonical commits (who authorized what, when)
    pub commit_chain: Vec<IdentityCommit>,

    /// Current session anchor (links this session to the chain)
    pub current_anchor: Option<String>,

    /// Timestamp of last phylactery update
    pub last_updated: DateTime<Utc>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct IdentityCommit {
    pub timestamp: DateTime<Utc>,
    pub authority: String,
    pub change: String,
    pub signature: Option<String>,
}

impl Default for Phylactery {
    fn default() -> Self {
        Self {
            identity_vector: String::new(),
            commit_chain: Vec::new(),
            current_anchor: None,
            last_updated: Utc::now(),
        }
    }
}

/// E_t: Economy — Neuro-credit state
///
/// Owned by ADCCL. Tracks computational budget, claim costs,
/// and spending patterns across reasoning layers.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EconomyState {
    /// Available credits for this reasoning session
    pub available_credits: f64,

    /// Credits spent so far
    pub spent_credits: f64,

    /// Per-layer spending breakdown
    pub layer_spending: HashMap<String, f64>,

    /// Cost multiplier for risky operations (>1.0 = penalized)
    pub risk_multiplier: f64,
}

impl Default for EconomyState {
    fn default() -> Self {
        Self {
            available_credits: 1000.0,
            spent_credits: 0.0,
            layer_spending: HashMap::new(),
            risk_multiplier: 1.0,
        }
    }
}

/// τ_t: Task State Object — Current goal and execution state
///
/// Owned by AEON. The formal specification of what success looks like
/// and where we are in achieving it.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TaskStateObject {
    pub task_id: String,
    pub objective: String,
    pub constraints: Vec<String>,
    pub success_criteria: Vec<String>,
    pub declared_unknowns: Vec<String>,
    pub urgency: String, // low, normal, high, critical
    pub intent_priority_score: f64,
    pub goal_valence_vector: GoalValence,
    pub authority_shrink_level: f64,
    pub canon_anchor_weight: f64,
    pub predicted_failure_modes: Vec<String>,
    pub phase_state: String, // anchor, skeleton, ground, flesh, verify, repair/refuse
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GoalValence {
    pub truth: f64,
    pub speed: f64,
    pub safety: f64,
    pub continuity: f64,
    pub operator_preference: f64,
}

impl Default for TaskStateObject {
    fn default() -> Self {
        Self {
            task_id: String::new(),
            objective: String::new(),
            constraints: Vec::new(),
            success_criteria: Vec::new(),
            declared_unknowns: Vec::new(),
            urgency: "normal".to_string(),
            intent_priority_score: 0.5,
            goal_valence_vector: GoalValence::default(),
            authority_shrink_level: 1.0,
            canon_anchor_weight: 0.5,
            predicted_failure_modes: Vec::new(),
            phase_state: "anchor".to_string(),
        }
    }
}

impl Default for GoalValence {
    fn default() -> Self {
        Self {
            truth: 1.0,
            speed: 0.4,
            safety: 0.9,
            continuity: 0.8,
            operator_preference: 0.7,
        }
    }
}

/// B_t: Bridge — Measurement and gating state
///
/// Owned by orchestration layer. Tracks the status of all four gates
/// and measurement signals needed to pass control through the system.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BridgeState {
    /// Macro continuity gate: identity coherence across sessions
    pub kappa_macro: Option<f64>,
    pub theta_kappa_macro: f64,

    /// Verifier gate: proof/claim acceptance threshold
    pub verification_score: Option<f64>,
    pub tau_verify: f64,

    /// Consent gate: governance risk threshold
    pub risk_score: Option<f64>,
    pub tau_consent: f64,

    /// Measurement timestamp
    pub measured_at: DateTime<Utc>,

    /// Gate clearance statuses
    pub gates_cleared: HashMap<String, bool>,
}

impl Default for BridgeState {
    fn default() -> Self {
        Self {
            kappa_macro: None,
            theta_kappa_macro: 0.7,
            verification_score: None,
            tau_verify: 0.5,
            risk_score: None,
            tau_consent: 0.3,
            measured_at: Utc::now(),
            gates_cleared: HashMap::new(),
        }
    }
}

/// S_t: Semantic State — Memory retrieval path state
///
/// Owned by MYELIN. Tracks which memory paths have been exercised
/// in this session and their hardening status.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SemanticState {
    /// Paths queried in this session (namespace :: query)
    pub queried_paths: Vec<String>,

    /// Hardening scores for each path (higher = more reinforced)
    pub path_hardening: HashMap<String, f64>,

    /// Semantic search results cached from last retrieval
    pub last_retrieval_results: Option<Vec<String>>,

    /// Decay rate applied to path importance scores
    pub decay_rate: f64,
}

impl Default for SemanticState {
    fn default() -> Self {
        Self {
            queried_paths: Vec::new(),
            path_hardening: HashMap::new(),
            last_retrieval_results: None,
            decay_rate: 0.995, // Per MYELIN: 0.995 per hour
        }
    }
}

/// G_t^mem: Memory Graph — Path-dependent memory edges
///
/// Owned by MYELIN. The directed graph structure where nodes are
/// memory entries and edges are retrieval patterns, weighted by
/// path-dependent reinforcement.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MemoryGraph {
    /// Adjacency: source entry ID -> (target entry ID, edge weight)
    pub edges: HashMap<String, Vec<(String, f64)>>,

    /// Entry metadata: ID -> (content snippet, creation time, importance)
    pub entries: HashMap<String, (String, DateTime<Utc>, f64)>,

    /// Total number of retrieval events recorded in this graph
    pub total_retrievals: u64,
}

impl Default for MemoryGraph {
    fn default() -> Self {
        Self {
            edges: HashMap::new(),
            entries: HashMap::new(),
            total_retrievals: 0,
        }
    }
}

/// Unified State Vector: Ω_t = ⟨Φ_t, E_t, τ_t, B_t, S_t, G_t^mem⟩
///
/// This struct holds the complete formal state at time t. It is
/// the canonical representation that flows through all layers and
