    /// Timestamp of state construction
    pub constructed_at: DateTime<Utc>,

    /// Parent state vector ID (for continuity tracing)
    pub parent_state_id: Option<String>,
}

impl Default for UnifiedStateVector {
    fn default() -> Self {
        Self {
            phylactery: Phylactery::default(),
            economy: EconomyState::default(),
            task: TaskStateObject::default(),
            bridge: BridgeState::default(),
            semantic: SemanticState::default(),
            memory_graph: MemoryGraph::default(),
            constructed_at: Utc::now(),
            parent_state_id: None,
        }
    }
}

impl UnifiedStateVector {
    /// Create a new state vector initialized with default values.
    pub fn new() -> Self {
        Self::default()
    }

    /// Compute the current yield functional:
    /// Y(aleph, tav_t, ω) = -ω·L_memory + (1-ω)·κ_continuity - D(aleph, tav_t)
    ///
    /// For now, returns a stub. Full implementation requires:
    /// - L_memory from MYELIN path-hardening statistics
    /// - κ_continuity from AEON phylactery coherence
    /// - D from goal distance metrics
    pub fn compute_yield(&self, _omega: f64) -> f64 {
        // TODO: wire to actual MYELIN and AEON computations
        0.0
    }

    /// Compute the current risk functional:
    /// R(aleph) = J_drift + R_risk
    ///
    /// For now, returns a stub. Full implementation requires:
    /// - J_drift from ADCCL verifier
    /// - R_risk from AEGIS governance gate
    pub fn compute_risk(&self) -> f64 {
        // TODO: wire to actual ADCCL and AEGIS computations
        0.0
    }

    /// Check if all three gates in the admissibility set 𝒞 are cleared:
    /// 1. κ_macro >= θ_κ (AEON: identity coherence)
    /// 2. V > τ_verify (ADCCL: verifier threshold)
    /// 3. R < τ_consent (AEGIS: risk boundary)
    pub fn check_admissibility(&self) -> bool {
        let gate_1 = self.bridge.kappa_macro
            .map(|v| v >= self.bridge.theta_kappa_macro)
            .unwrap_or(false);

        let gate_2 = self.bridge.verification_score
            .map(|v| v > self.bridge.tau_verify)
            .unwrap_or(false);

        let gate_3 = self.bridge.risk_score
            .map(|v| v < self.bridge.tau_consent)
            .unwrap_or(false);

        gate_1 && gate_2 && gate_3
    }
}

